const envelope = $json.body ?? $json;
const payload = envelope.payload ?? envelope;
const search = payload.search ?? {};
const callback = payload.callback ?? envelope.callback ?? {};
const preference = payload.preference ?? {};

function text(value, fallback = '') {
  if (value === null || value === undefined) return fallback;
  return String(value).trim();
}

function integer(value, fallback, min = 0, max = 99999) {
  const parsed = Number.parseInt(value, 10);
  if (!Number.isFinite(parsed)) return fallback;
  return Math.max(min, Math.min(max, parsed));
}

function boolean(value, fallback = false) {
  if (value === true || value === false) return value;
  const normalized = text(value).toLowerCase();
  if (['1', 'true', 'sim', 'yes', 'on'].includes(normalized)) return true;
  if (['0', 'false', 'nao', 'não', 'no', 'off'].includes(normalized)) return false;
  return fallback;
}

function normalizedOffset(value) {
  const offset = text(value, '-03:00');
  return /^[+-]\d{2}:\d{2}$/.test(offset) ? offset : '-03:00';
}

function toIso(value, offset) {
  const source = text(value);
  if (!source) return '';
  if (/Z$|[+-]\d{2}:\d{2}$/.test(source)) return new Date(source).toISOString();
  const normalized = source.replace(' ', 'T').replace(/\.\d+$/, '');
  return new Date(`${normalized}${offset}`).toISOString();
}

const utcOffset = normalizedOffset(search.utc_offset || payload.google_utc_offset || '-03:00');
const startAt = text(search.start_at || payload.search_start_at);
const endAt = text(search.end_at || payload.search_end_at);
const windowStartIso = toIso(startAt, utcOffset);
const windowEndIso = toIso(endAt, utcOffset);
if (!windowStartIso || !windowEndIso || new Date(windowStartIso) >= new Date(windowEndIso)) {
  throw new Error('A janela de busca recebida é inválida.');
}

const calendarId = text(search.calendar_id || payload.calendar_id, 'primary');
const encodedCalendar = encodeURIComponent(calendarId);
const googleListUrl = `https://www.googleapis.com/calendar/v3/calendars/${encodedCalendar}/events?singleEvents=true&orderBy=startTime&showDeleted=false&maxResults=2500&timeMin=${encodeURIComponent(windowStartIso)}&timeMax=${encodeURIComponent(windowEndIso)}`;
const workdays = Array.isArray(search.workdays) ? search.workdays.map(Number).filter(day => Number.isInteger(day) && day >= 0 && day <= 6) : [1, 2, 3, 4, 5];

return [{
  json: {
    tenant_id: Number(payload.tenant_id || envelope.tenant_id || 0),
    appointment_id: payload.appointment_id ? Number(payload.appointment_id) : null,
    conversation_id: payload.conversation_id ? Number(payload.conversation_id) : null,
    contact_id: payload.contact_id ? Number(payload.contact_id) : null,
    request_id: Number(payload.request_id || 0),
    request_token: text(payload.request_token || callback.token),
    callback_url: text(callback.url, 'https://rsconnect.rsautomacaodigital.cloud/webhooks/calendar/availability'),
    availability_mode: 'free_slots',
    calendar_id: calendarId,
    google_list_url: googleListUrl,
    timezone: text(search.timezone, 'America/Sao_Paulo'),
    utc_offset: utcOffset,
    search_start_at: startAt,
    search_end_at: endAt,
    window_start_iso: windowStartIso,
    window_end_iso: windowEndIso,
    working_start: text(search.working_start, '08:00'),
    working_end: text(search.working_end, '18:00'),
    workdays: workdays.length ? workdays : [1, 2, 3, 4, 5],
    duration_minutes: integer(search.duration_minutes, 50, 5, 720),
    slot_interval_minutes: integer(search.slot_interval_minutes, 30, 5, 720),
    buffer_minutes: integer(search.buffer_minutes, 0, 0, 720),
    min_notice_minutes: integer(search.min_notice_hours, 0, 0, 720) * 60,
    max_suggestions: integer(search.max_suggestions, 5, 1, 200),
    ignore_transparent_events: boolean(search.ignore_transparent_events, true),
    preferred_start_at: text(preference.starts_at || payload.appointment?.starts_at),
    original: envelope
  }
}];

const cfg = $('Normalizar pedido').first().json;
const response = $json ?? {};
const events = Array.isArray(response.items) ? response.items : [];

function offsetMinutes(offset) {
  const sign = offset.startsWith('-') ? -1 : 1;
  const [hours, minutes] = offset.slice(1).split(':').map(Number);
  return sign * ((hours || 0) * 60 + (minutes || 0));
}

const offset = offsetMinutes(cfg.utc_offset);

function localSql(date) {
  const shifted = new Date(date.getTime() + offset * 60000);
  return shifted.toISOString().slice(0, 19).replace('T', ' ');
}

function localLabel(date) {
  const shifted = new Date(date.getTime() + offset * 60000);
  const iso = shifted.toISOString();
  return `${iso.slice(8, 10)}/${iso.slice(5, 7)}/${iso.slice(0, 4)} ${iso.slice(11, 16)}`;
}

function localDateKey(date) {
  const shifted = new Date(date.getTime() + offset * 60000);
  return shifted.toISOString().slice(0, 10);
}

function localDateTime(dateKey, time) {
  return new Date(`${dateKey}T${time}:00${cfg.utc_offset}`);
}

function eventDate(value, allDayEnd = false) {
  if (!value) return null;
  if (value.dateTime) return new Date(value.dateTime);
  if (value.date) return new Date(`${value.date}T00:00:00${cfg.utc_offset}`);
  return null;
}

function overlaps(startA, endA, startB, endB) {
  return startA < endB && startB < endA;
}

const globalStart = new Date(cfg.window_start_iso);
const globalEnd = new Date(cfg.window_end_iso);
const earliestAllowed = new Date(Date.now() + cfg.min_notice_minutes * 60000);
const bufferMs = cfg.buffer_minutes * 60000;

const busy = events
  .filter(event => {
    if (!event || String(event.status || '').toLowerCase() === 'cancelled') return false;
    if (cfg.ignore_transparent_events && String(event.transparency || 'opaque').toLowerCase() === 'transparent') return false;
    return true;
  })
  .map(event => {
    const start = eventDate(event.start);
    const end = eventDate(event.end, true);
    return start && end ? {
      start: new Date(start.getTime() - bufferMs),
      end: new Date(end.getTime() + bufferMs),
      id: event.id || null,
      summary: event.summary || ''
    } : null;
  })
  .filter(Boolean);

const firstDate = localDateKey(globalStart);
const lastDate = localDateKey(new Date(globalEnd.getTime() - 1));
const dayCursor = new Date(`${firstDate}T00:00:00Z`);
const finalDay = new Date(`${lastDate}T00:00:00Z`);
const candidates = [];

for (let day = new Date(dayCursor); day <= finalDay; day = new Date(day.getTime() + 86400000)) {
  const dateKey = day.toISOString().slice(0, 10);
  const weekday = day.getUTCDay();
  if (!cfg.workdays.includes(weekday)) continue;

  const businessStart = localDateTime(dateKey, cfg.working_start);
  const businessEnd = localDateTime(dateKey, cfg.working_end);
  if (Number.isNaN(businessStart.getTime()) || Number.isNaN(businessEnd.getTime()) || businessStart >= businessEnd) continue;

  for (let slotStart = new Date(businessStart); slotStart < businessEnd; slotStart = new Date(slotStart.getTime() + cfg.slot_interval_minutes * 60000)) {
    const slotEnd = new Date(slotStart.getTime() + cfg.duration_minutes * 60000);
    if (slotEnd > businessEnd || slotStart < globalStart || slotEnd > globalEnd || slotStart < earliestAllowed) continue;
    if (busy.some(event => overlaps(slotStart, slotEnd, event.start, event.end))) continue;

    candidates.push({
      startDate: slotStart,
      endDate: slotEnd,
      start: localSql(slotStart),
      end: localSql(slotEnd),
      label: localLabel(slotStart),
      modality: 'indefinida',
      google_event_id: null,
      google_calendar_id: cfg.calendar_id,
      source: 'google_free_slots'
    });
  }
}

let preferred = null;
if (cfg.preferred_start_at) {
  const value = /Z$|[+-]\d{2}:\d{2}$/.test(cfg.preferred_start_at)
    ? cfg.preferred_start_at
    : `${cfg.preferred_start_at.replace(' ', 'T')}${cfg.utc_offset}`;
  const parsed = new Date(value);
  if (!Number.isNaN(parsed.getTime())) preferred = parsed;
}

candidates.sort((a, b) => {
  if (preferred) {
    const distanceA = Math.abs(a.startDate.getTime() - preferred.getTime());
    const distanceB = Math.abs(b.startDate.getTime() - preferred.getTime());
    if (distanceA !== distanceB) return distanceA - distanceB;
  }
  return a.startDate - b.startDate;
});

const slots = candidates.slice(0, cfg.max_suggestions).map(({ startDate, endDate, ...slot }) => slot);
const callbackPayload = {
  event: 'calendar.availability.result',
  ok: true,
  tenant_id: cfg.tenant_id,
  appointment_id: cfg.appointment_id,
  request_id: cfg.request_id,
  request_token: cfg.request_token,
  source: 'google_free_slots',
  google_calendar_id: cfg.calendar_id,
  slots,
  meta: {
    events_read: events.length,
    occupied_events_considered: busy.length,
    transparent_events_ignored: cfg.ignore_transparent_events,
    duration_minutes: cfg.duration_minutes,
    slot_interval_minutes: cfg.slot_interval_minutes,
    buffer_minutes: cfg.buffer_minutes
  }
};

return [{ json: { ...cfg, slots, callback_payload: callbackPayload } }];
